#include <iostream>
#include <string>

class Shape
{
protected:
    std::string m_name;

public:
    Shape(const std::string& name)
        : m_name{name}
    {
    }

    virtual ~Shape() = default;

    virtual void print(std::ostream& out) const
    {
        out << "[Shape: " << m_name << "]";
    }

    friend std::ostream& operator<<(std::ostream& out, const Shape& s)
    {
        s.print(out);
        return out;
    }
};

class Circle : public Shape
{
    double m_radius{};

public:
    Circle(const std::string& name, double radius)
        : Shape{name}
        , m_radius{radius}
    {
    }

    void print(std::ostream& out) const override
    {
        out << "[Circle: " << m_name << ", r=" << m_radius << "]";
    }
};

int main()
{
    std::string name{};
    double radius{};
    std::cin >> name >> radius;

    Shape shape{name};
    std::cout << shape << '\n';

    Circle circle{name, radius};
    std::cout << circle << '\n';

    const Shape& ref{circle};
    std::cout << ref << '\n';

    return 0;
}

