#include <iostream>
#include <string>
#include <vector>

class Employee
{
protected:
    std::string m_name;

public:
    Employee(const std::string& name)
        : m_name{name}
    {
    }

    virtual ~Employee() = default;

    virtual void print(std::ostream& out) const
    {
        out << "Employee: " << m_name;
    }

    friend std::ostream& operator<<(std::ostream& out, const Employee& e)
    {
        e.print(out);
        return out;
    }
};

class Manager : public Employee
{
    std::string m_dept;

public:
    Manager(const std::string& name, const std::string& dept)
        : Employee{name}
        , m_dept{dept}
    {
    }

    void print(std::ostream& out) const override
    {
        out << "Manager: " << m_name << ", dept=" << m_dept;
    }
};

class Engineer : public Employee
{
    std::string m_lang;

public:
    Engineer(const std::string& name, const std::string& lang)
        : Employee{name}
        , m_lang{lang}
    {
    }

    void print(std::ostream& out) const override
    {
        out << "Engineer: " << m_name << ", lang=" << m_lang;
    }
};

int main()
{
    int n{};
    std::cin >> n;

    std::vector<Employee*> employees{};

    for (int i{0}; i < n; ++i)
    {
        std::string type{};
        std::cin >> type;

        if (type == "manager")
        {
            std::string name{}, dept{};
            std::cin >> name >> dept;
            employees.push_back(new Manager{name, dept});
        }
        else
        {
            std::string name{}, lang{};
            std::cin >> name >> lang;
            employees.push_back(new Engineer{name, lang});
        }
    }

    for (const auto* e : employees)
    {
        std::cout << *e << '\n';
    }

    std::cout << "Total: " << n << '\n';

    for (auto* e : employees)
    {
        delete e;
    }

    return 0;
}
